#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.heightIndicator)]
    public class HeightIndicatorOptionToggle : OptionToggleDefinition
    {
        public HeightIndicatorOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetOptionBool(LogicOptionItemID.heightIndicator);
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetOptionBool(LogicOptionItemID.heightIndicator, value);
            Global.Options.SaveOptions();
        }
    }
}
